function f(e,r=0){if(typeof e=="number")return Number.isFinite(e)?e:r;if(typeof e=="string"){const n=Number(e);return Number.isFinite(n)?n:r}return r}function u(e){if(!e)return"never";const r=typeof e=="number"&&e<1e12?e*1e3:e,n=Date.now()-new Date(r).getTime(),t=Math.floor(n/1e3);if(t<60)return t+"s ago";const o=Math.floor(t/60);if(o<60)return o+"m ago";const i=Math.floor(o/60);return i<24?i+"h ago":Math.floor(i/24)+"d ago"}export{f as s,u as t};
